from itertools import cycle
from functools import lru_cache

#input_signal = "" *10000
input_signal = "03036732577212944063491565474664" *10000
input_signal = "02935109699940807407585447034323" *10000
input_signal = "03081770884921959731165446850517" *10000
offset = int(input_signal[:7])

input_signal = input_signal[offset:]

for r in range(100):
  print(f"Round",r)
  next_phrase = ""
  running_total = 0
  for row in range(len(input_signal)-1, -1, -1):
    running_total += int(input_signal[row])
    next_phrase = str(running_total)[-1] + next_phrase
  input_signal = next_phrase
print(next_phrase[:8])
